const Redis = global.get('redis');
if (!Redis) {
    node.error('Redis client not available in global context');
    return null;
}
const key = msg.payload;
if (!key || typeof key !== 'string') {
    node.warn('Invalid Redis key: ' + JSON.stringify(key));
    return null;
}
try {
    const value = await Redis.get(key);
    if (value !== null) {
        // Try to parse JSON, fall back to string
        try { msg.payload = JSON.parse(value); }
        catch(e) { msg.payload = value; }
    } else {
        msg.payload = null;
    }
    return msg;
} catch(e) {
    node.error('Redis read error: ' + e.message);
    return null;
}
